"use client"

import * as React from "react"
import {
  AlertCircleIcon,
  AlertTriangleIcon,
  BarChart3Icon,
  ChevronDownIcon,
  ChevronRightIcon,
  CircleCheckIcon,
  CopyIcon,
  FilterIcon,
  ListIcon,
  MoreVerticalIcon,
  SearchIcon,
  TableIcon,
} from "lucide-react"

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/registry/default/ui/dropdown-menu"
import { Input } from "@/registry/default/ui/input"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/registry/default/ui/table"
import {
  useTranslation,
  type Translations,
} from "@/hooks/use-translation"
import { cn } from "@/lib/utils"

export type ModelTableStatus = "fail" | "warn" | "pass" | "none"

export type ModelTableRuleStatus = "pass" | "warn" | "fail"

export type ModelTableQualityRule = {
  id: string
  column: string
  rule: string
  status: ModelTableRuleStatus
}

export type ModelTableErrorDetail = {
  errorType: string
  message: string
  viewMoreLabel?: string
  viewMoreHref?: string
  onViewMore?: () => void
}

export type ModelTableRow = {
  id: string
  name: string
  namespace: string
  kind: string
  type: string
  runtimeMs?: number
  rowCount?: number
  rowCountLabel?: string
  dataSize?: string
  status?: ModelTableStatus
  statusCount?: number
  hasError?: boolean
  showSparkline?: boolean
  expansion?: "error" | "quality"
  errorDetail?: ModelTableErrorDetail
  qualityRules?: ModelTableQualityRule[]
}

export type ModelsTableProps = {
  title?: string
  rows?: ModelTableRow[]
  searchPlaceholder?: string
  searchQuery?: string
  defaultSearchQuery?: string
  onSearchChange?: (query: string) => void
  enableSearch?: boolean
  enableSort?: boolean
  enableExpand?: boolean
  expandedIds?: string[]
  defaultExpandedIds?: string[]
  onExpandedChange?: (ids: string[]) => void
  className?: string
}

export const modelsTableMessages = {
  en: {
    dir: "ltr",
    values: {
      title: "Models",
      searchPlaceholder: "Search by keywords",
      columnModel: "Model",
      columnKindType: "Kind / Type",
      columnRuntime: "Runtime",
      columnRows: "Rows",
      columnStatus: "Status",
      columnColumn: "Column",
      columnRule: "Rule",
      notEval: "Not eval",
      viewMore: "View more",
      tableLevelRule: "table-level rule",
      noModelsFound: "No models found.",
      sortModels: "Sort models",
      copyError: "Copy error message",
      filterKindType: "kind and type",
      filterRuntime: "runtime",
      filterRows: "rows",
      filterStatus: "status",
      filterPrefix: "Filter",
      actionsFor: "Actions for",
      viewRunLog: "View run log",
      openInEditor: "Open in editor",
      copyModelName: "Copy model name",
      expand: "Expand",
      collapse: "Collapse",
    },
  },
  es: {
    dir: "ltr",
    values: {
      title: "Modelos",
      searchPlaceholder: "Buscar por palabras clave",
      columnModel: "Modelo",
      columnKindType: "Tipo / Clase",
      columnRuntime: "Duración",
      columnRows: "Filas",
      columnStatus: "Estado",
      columnColumn: "Columna",
      columnRule: "Regla",
      notEval: "Sin eval",
      viewMore: "Ver más",
      tableLevelRule: "regla a nivel de tabla",
      noModelsFound: "No se encontraron modelos.",
      sortModels: "Ordenar modelos",
      copyError: "Copiar mensaje de error",
      filterKindType: "tipo y clase",
      filterRuntime: "duración",
      filterRows: "filas",
      filterStatus: "estado",
      filterPrefix: "Filtrar",
      actionsFor: "Acciones para",
      viewRunLog: "Ver registro de ejecución",
      openInEditor: "Abrir en el editor",
      copyModelName: "Copiar nombre del modelo",
      expand: "Expandir",
      collapse: "Contraer",
    },
  },
} satisfies Translations

const defaultQualityRules: ModelTableQualityRule[] = [
  {
    id: "r1",
    column: "table-level rule",
    rule: "total number of orders ingested today should be within 10% of the 7-day average",
    status: "warn",
  },
  {
    id: "r2",
    column: "contract_id",
    rule: "should be unique and not null",
    status: "pass",
  },
  {
    id: "r3",
    column: "building_id",
    rule: "should not be null",
    status: "warn",
  },
  {
    id: "r4",
    column: "maintenance_cost",
    rule: "should be >= 0",
    status: "pass",
  },
]

const defaultRows: ModelTableRow[] = [
  {
    id: "m3",
    name: "BUILDING_COMPETITORS_AGG",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "INCREMENTAL_BY_UNIQUE_KEY",
    type: "SQL",
    runtimeMs: 142,
    rowCount: 24830,
    dataSize: "1gb",
    status: "warn",
    statusCount: 1,
    showSparkline: true,
    expansion: "quality",
    qualityRules: defaultQualityRules,
  },
  {
    id: "m4",
    name: "CONTRACT_HISTORY",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "EXTERNAL",
    type: "SQL",
    runtimeMs: 28,
    rowCount: 13200,
    dataSize: "750mb",
    status: "warn",
    statusCount: 1,
    showSparkline: true,
  },
  {
    id: "m5",
    name: "MAINT_COST",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "VIEW",
    type: "ROLLUP",
    runtimeMs: 315,
    rowCount: 30110,
    dataSize: "2gb",
    status: "pass",
    statusCount: 8,
    showSparkline: true,
  },
  {
    id: "m6",
    name: "MAINT_COST",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "INCREMENTAL_BY_PARTITION",
    type: "SQL",
    runtimeMs: 67,
    rowCount: 8900,
    dataSize: "400mb",
    status: "pass",
    statusCount: 12,
    showSparkline: true,
  },
  {
    id: "m7",
    name: "MAINT_COST",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "SEED",
    type: "PYTHON",
    runtimeMs: 189,
    rowCount: 22475,
    dataSize: "1.5gb",
    status: "pass",
    statusCount: 6,
    showSparkline: true,
  },
  {
    id: "m8",
    name: "QUOTE_DETAIL",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "FULL",
    type: "ROLLUP",
    runtimeMs: 43,
    rowCount: 17320,
    dataSize: "600mb",
    status: "none",
    showSparkline: true,
  },
  {
    id: "m9",
    name: "QUOTE_DETAIL",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "FULL",
    type: "ROLLUP",
    runtimeMs: 256,
    rowCount: 26700,
    dataSize: "3gb",
    status: "none",
    showSparkline: true,
  },
  {
    id: "m10",
    name: "MAINT_COST",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "VIEW",
    type: "ROLLUP",
    runtimeMs: 94,
    rowCount: 11245,
    dataSize: "850mb",
    status: "none",
    showSparkline: true,
  },
  {
    id: "m1",
    name: "BUILDING_COMPETITORS_AGG",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "INCREMENTAL_BY_UNIQUE_KEY",
    type: "SQL",
    status: "fail",
    statusCount: 1,
    hasError: true,
    showSparkline: true,
    expansion: "error",
    errorDetail: {
      errorType: "Py4JJavaError",
      message:
        "Could not establish connection to warehouse 'TRANSFORM_WH': authentication token expired (390114). Retried 3x.\n    at Connection.open (driver.js:64:11)",
      viewMoreLabel: "View more",
    },
  },
  {
    id: "m2",
    name: "CONTRACT_HISTORY",
    namespace: "SFDATAPRODUC... / SALES",
    kind: "FULL",
    type: "ROLLUP",
    status: "fail",
    statusCount: 1,
    hasError: true,
  },
]

const headerIconClassName =
  "text-muted-foreground hover:text-foreground inline-flex size-4 shrink-0 items-center justify-center rounded-sm transition-colors"

function isExpandable(row: ModelTableRow) {
  return Boolean(
    row.expansion &&
      (row.expansion === "error"
        ? row.errorDetail
        : row.qualityRules && row.qualityRules.length > 0)
  )
}

function ColumnSortIcon({
  direction,
}: {
  direction: false | "asc" | "desc"
}) {
  return (
    <span
      className="inline-flex flex-col items-center gap-0.5 leading-none"
      aria-hidden
    >
      <svg
        viewBox="0 0 8 5"
        className={cn(
          "h-1.5 w-3",
          direction === "asc" ? "text-foreground" : "text-muted-foreground/45"
        )}
      >
        <path fill="currentColor" d="M4 0 8 5H0z" />
      </svg>
      <svg
        viewBox="0 0 8 5"
        className={cn(
          "h-1.5 w-3",
          direction === "desc" ? "text-foreground" : "text-muted-foreground/45"
        )}
      >
        <path fill="currentColor" d="M0 0h8L4 5z" />
      </svg>
    </span>
  )
}

function HeaderDivider() {
  return (
    <span
            className="bg-border pointer-events-none absolute top-1/2 start-0 h-4 w-px -translate-y-1/2"
      aria-hidden
    />
  )
}

function HeaderFilterButton({ label }: { label: string }) {
  const { t } = useTranslation(modelsTableMessages)
  return (
    <button
      type="button"
      className={headerIconClassName}
      aria-label={`${t.filterPrefix} ${label}`}
    >
      <FilterIcon className="size-3" />
    </button>
  )
}

function KindTypePill({ label }: { label: string }) {
  return (
    <span className="inline-flex max-w-full rounded px-2 py-1 font-mono text-[10px] font-medium tracking-wide text-[#242422] uppercase bg-[#ececec] dark:bg-white/90 dark:text-[#242422]">
      <span className="truncate">{label}</span>
    </span>
  )
}

function RuntimeBar({
  runtimeMs,
  maxRuntimeMs,
}: {
  runtimeMs: number
  maxRuntimeMs: number
}) {
  const width = maxRuntimeMs > 0 ? Math.max(8, (runtimeMs / maxRuntimeMs) * 100) : 0

  return (
    <div className="flex min-w-[6.5rem] items-center gap-2 sm:min-w-[7rem]">
      <div className="h-1.5 min-w-0 flex-1 overflow-hidden rounded-full bg-[#ececec] dark:bg-white/90">
        <div
          className="bg-model-health-healthy h-full rounded-full transition-[width]"
          style={{ width: `${width}%` }}
        />
      </div>
      <span className="text-muted-foreground shrink-0 text-xs tabular-nums">
        {runtimeMs}ms
      </span>
    </div>
  )
}

function RuleStatusIcon({ status }: { status: ModelTableRuleStatus }) {
  if (status === "fail") {
    return (
      <AlertCircleIcon className="size-4 shrink-0 fill-dataos-fail-bg text-dataos-fail-fg" />
    )
  }
  if (status === "warn") {
    return (
      <AlertTriangleIcon className="size-4 shrink-0 fill-[#FFF1DE] text-[#E68600]" />
    )
  }
  return (
    <CircleCheckIcon className="size-4 shrink-0 fill-dataos-success-bg text-dataos-success-fg" />
  )
}

function StatusCell({ row }: { row: ModelTableRow }) {
  const { t } = useTranslation(modelsTableMessages)
  if (!row.status || row.status === "none") {
    return (
      <span className="text-muted-foreground text-sm italic">{t.notEval}</span>
    )
  }

  if (row.status === "fail") {
    return (
      <span className="text-dataos-fail-fg inline-flex items-center gap-1.5 text-sm font-medium">
        <AlertCircleIcon className="size-4 shrink-0 fill-dataos-fail-bg" />
        {row.statusCount}
      </span>
    )
  }

  if (row.status === "warn") {
    return (
      <span className="inline-flex items-center gap-1.5 text-sm font-medium text-[#E68600]">
        <AlertTriangleIcon className="size-4 shrink-0 fill-[#FFF1DE]" />
        {row.statusCount}
      </span>
    )
  }

  return (
    <span className="text-dataos-success-fg inline-flex items-center gap-1.5 text-sm font-medium">
      <CircleCheckIcon className="size-4 shrink-0 fill-dataos-success-bg" />
      {row.statusCount}
    </span>
  )
}

function formatRowCount(row: ModelTableRow) {
  if (row.rowCount == null) return "—"
  return row.rowCountLabel ?? row.rowCount.toLocaleString("en-US")
}

function RowActionsMenu({ row }: { row: ModelTableRow }) {
  const { t } = useTranslation(modelsTableMessages)
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button
          type="button"
          className={cn(headerIconClassName, "size-7")}
          aria-label={`${t.actionsFor} ${row.name}`}
          onClick={(event) => event.stopPropagation()}
        >
          <MoreVerticalIcon className="size-4" />
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-40">
        <DropdownMenuItem>{t.viewRunLog}</DropdownMenuItem>
        <DropdownMenuItem>{t.openInEditor}</DropdownMenuItem>
        <DropdownMenuItem>{t.copyModelName}</DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

function ErrorExpansionPanel({ detail }: { detail: ModelTableErrorDetail }) {
  const { t } = useTranslation(modelsTableMessages)
  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(detail.message)
    } catch {
      // Clipboard unavailable
    }
  }

  const showViewMore =
    Boolean(detail.viewMoreLabel) ||
    Boolean(detail.viewMoreHref) ||
    Boolean(detail.onViewMore)
  const viewMoreLabel = detail.viewMoreLabel ?? t.viewMore

  return (
    <div className="px-3 pb-5 ps-10 sm:px-4 sm:ps-11">
      <div className="mb-3">
        <span className="border-dataos-fail-fg text-dataos-fail-fg inline-flex rounded border bg-white px-2 py-0.5 text-xs font-medium dark:bg-transparent">
          {detail.errorType}
        </span>
      </div>
      <div className="relative rounded-lg bg-cream-bg-1 p-4">
        <button
          type="button"
          onClick={handleCopy}
          className="text-muted-foreground hover:text-foreground absolute top-3 end-3 inline-flex size-7 items-center justify-center rounded-sm transition-colors"
          aria-label={t.copyError}
        >
          <CopyIcon className="size-3.5" />
        </button>
        <p className="text-foreground pe-9 font-mono text-xs leading-relaxed whitespace-pre-wrap">
          {detail.message}
        </p>
        {showViewMore ? (
          detail.viewMoreHref ? (
            <a
              href={detail.viewMoreHref}
              className="text-primary mt-3 inline-block text-sm font-medium hover:underline"
            >
              {viewMoreLabel}
            </a>
          ) : (
            <button
              type="button"
              onClick={detail.onViewMore}
              className="text-primary mt-3 text-sm font-medium hover:underline"
            >
              {viewMoreLabel}
            </button>
          )
        ) : null}
      </div>
    </div>
  )
}

function isTableLevelRule(column: string) {
  return column === "—" || column.toLowerCase() === "table-level rule"
}

function QualityExpansionPanel({ rules }: { rules: ModelTableQualityRule[] }) {
  const { t } = useTranslation(modelsTableMessages)
  return (
    <div className="w-full bg-cream-bg-3">
      <table className="w-full table-fixed text-start text-sm">
        <colgroup>
          <col className="w-[33%]" />
          <col className="w-[46%]" />
          <col className="w-[13%]" />
          <col className="w-[8%]" />
        </colgroup>
        <thead>
          <tr className="border-b border-border">
            <th className="text-muted-foreground h-9 ps-10 text-xs font-medium">
              {t.columnColumn}
            </th>
            <th className="text-muted-foreground relative h-9 px-3 text-xs font-medium sm:px-4">
              <HeaderDivider />
              {t.columnRule}
            </th>
            <th className="text-muted-foreground relative h-9 px-3 text-xs font-medium sm:px-4">
              <HeaderDivider />
              {t.columnStatus}
            </th>
            <th className="relative h-9 px-2 sm:px-3">
              <HeaderDivider />
            </th>
          </tr>
        </thead>
        <tbody>
          {rules.map((rule) => {
            const tableLevel = isTableLevelRule(rule.column)

            return (
              <tr
                key={rule.id}
                className="border-b border-border/70 last:border-0"
              >
                <td className="px-3 py-3 ps-10">
                  <div className="flex min-w-0 items-center gap-2">
                    <span className="inline-flex size-4 shrink-0 items-center justify-center">
                      <TableIcon className="text-muted-foreground size-3.5" />
                    </span>
                    <span
                      className={cn(
                        "text-foreground truncate",
                        tableLevel ? "italic" : "font-mono text-[13px]"
                      )}
                    >
                      {tableLevel ? t.tableLevelRule : rule.column}
                    </span>
                  </div>
                </td>
                <td className="text-foreground truncate px-3 py-3 sm:px-4">
                  {rule.rule}
                </td>
                <td className="px-3 py-3 sm:px-4">
                  <RuleStatusIcon status={rule.status} />
                </td>
                <td className="px-2 py-3 sm:px-3" />
              </tr>
            )
          })}
        </tbody>
      </table>
    </div>
  )
}

function ExpandButton({
  expanded,
  expandable,
  enableExpand,
  onToggleExpand,
  name,
}: {
  expanded: boolean
  expandable: boolean
  enableExpand: boolean
  onToggleExpand: () => void
  name: string
}) {
  const { t } = useTranslation(modelsTableMessages)
  if (!enableExpand || !expandable) {
    return <ChevronRightIcon className="text-muted-foreground mt-0.5 size-4 shrink-0" />
  }

  return (
    <button
      type="button"
      onClick={onToggleExpand}
      className="text-muted-foreground hover:text-foreground mt-0.5 inline-flex size-4 shrink-0 items-center justify-center rounded-sm transition-colors"
      aria-expanded={expanded}
      aria-label={
        expanded ? `${t.collapse} ${name}` : `${t.expand} ${name}`
      }
    >
      {expanded ? (
        <ChevronDownIcon className="size-4" />
      ) : (
        <ChevronRightIcon className="size-4" />
      )}
    </button>
  )
}

function ModelTableDataRow({
  row,
  maxRuntimeMs,
  expanded,
  expandable,
  enableExpand,
  onToggleExpand,
}: {
  row: ModelTableRow
  maxRuntimeMs: number
  expanded: boolean
  expandable: boolean
  enableExpand: boolean
  onToggleExpand: () => void
}) {
  const showDash = row.hasError || row.runtimeMs == null

  return (
    <TableRow className="group border-border bg-transparent hover:bg-muted/40">
      <TableCell
        className={cn(
          "relative whitespace-normal px-3 py-4 align-middle sm:px-4",
          row.hasError &&
            "before:bg-destructive before:absolute before:inset-y-0 before:start-0 before:w-0.5"
        )}
      >
        <div className="flex min-w-0 items-start gap-2">
          <ExpandButton
            expanded={expanded}
            expandable={expandable}
            enableExpand={enableExpand}
            onToggleExpand={onToggleExpand}
            name={row.name}
          />
          <div className="min-w-0">
            <p className="text-foreground truncate text-sm font-semibold uppercase">
              {row.name}
            </p>
            <p className="text-muted-foreground mt-0.5 truncate text-xs italic">
              {row.namespace}
            </p>
          </div>
        </div>
      </TableCell>
      <TableCell className="whitespace-normal px-3 py-4 align-middle sm:px-4">
        <div className="flex min-w-0 flex-wrap gap-1.5">
          <KindTypePill label={row.kind} />
          <KindTypePill label={row.type} />
        </div>
      </TableCell>
      <TableCell className="whitespace-normal px-3 py-4 align-middle sm:px-4">
        {showDash ? (
          <span className="text-muted-foreground text-sm">—</span>
        ) : (
          <RuntimeBar runtimeMs={row.runtimeMs!} maxRuntimeMs={maxRuntimeMs} />
        )}
      </TableCell>
      <TableCell className="whitespace-normal px-3 py-4 align-middle sm:px-4">
        <div className="min-w-0">
          {showDash && row.rowCount == null ? (
            <span className="text-muted-foreground text-sm">—</span>
          ) : (
            <>
              <p className="text-foreground text-sm tabular-nums">{formatRowCount(row)}</p>
              {row.dataSize ? (
                <p className="text-muted-foreground text-xs">{row.dataSize}</p>
              ) : null}
            </>
          )}
        </div>
      </TableCell>
      <TableCell className="whitespace-normal px-3 py-4 align-middle sm:px-4">
        <StatusCell row={row} />
      </TableCell>
      <TableCell className="whitespace-normal px-2 py-4 align-middle sm:px-3">
        <div className="flex min-w-[3.5rem] items-center justify-end gap-1">
          {row.showSparkline ? (
            <BarChart3Icon className="text-muted-foreground/60 hidden size-4 shrink-0 sm:block" />
          ) : null}
          <span className="opacity-0 transition-opacity group-hover:opacity-100 focus-within:opacity-100">
            <RowActionsMenu row={row} />
          </span>
        </div>
      </TableCell>
    </TableRow>
  )
}

function ModelTableExpandedRow({
  row,
  columnCount,
  onToggleExpand,
}: {
  row: ModelTableRow
  columnCount: number
  onToggleExpand: () => void
}) {
  const { t } = useTranslation(modelsTableMessages)
  return (
    <TableRow className="border-border !bg-cream-bg-3 hover:!bg-cream-bg-3">
      <TableCell
        colSpan={columnCount}
        className={cn(
          "relative !bg-cream-bg-3 p-0",
          row.hasError &&
            "before:bg-destructive before:absolute before:inset-y-0 before:start-0 before:z-10 before:w-0.5"
        )}
      >
        <div className="bg-cream-bg-3">
          <div className="grid w-full grid-cols-[33%_46%_13%_8%] items-start py-0">
            <div className="flex min-w-0 items-start gap-2 px-3 py-4 sm:px-4">
              <button
                type="button"
                onClick={onToggleExpand}
                className="text-muted-foreground hover:text-foreground mt-0.5 inline-flex size-4 shrink-0 items-center justify-center rounded-sm transition-colors"
                aria-expanded="true"
                aria-label={`${t.collapse} ${row.name}`}
              >
                <ChevronDownIcon className="size-4" />
              </button>
              <div className="min-w-0">
                <p className="text-foreground truncate text-sm font-semibold uppercase">
                  {row.name}
                </p>
                <p className="text-muted-foreground mt-0.5 truncate text-xs italic">
                  {row.namespace}
                </p>
              </div>
            </div>
            <div />
            <div />
            <div className="flex items-center justify-end gap-1 px-2 py-[1.3rem] sm:px-3">
              {row.showSparkline ? (
                <BarChart3Icon className="text-muted-foreground/60 size-4 shrink-0" />
              ) : null}
              <RowActionsMenu row={row} />
            </div>
          </div>
          {row.expansion === "error" && row.errorDetail ? (
            <ErrorExpansionPanel detail={row.errorDetail} />
          ) : null}
          {row.expansion === "quality" && row.qualityRules ? (
            <QualityExpansionPanel rules={row.qualityRules} />
          ) : null}
        </div>
      </TableCell>
    </TableRow>
  )
}

export function ModelsTable({
  title,
  rows = defaultRows,
  searchPlaceholder,
  searchQuery,
  defaultSearchQuery = "",
  onSearchChange,
  enableSearch = true,
  enableSort = true,
  enableExpand = true,
  expandedIds,
  defaultExpandedIds,
  onExpandedChange,
  className,
}: ModelsTableProps) {
  const { t } = useTranslation(modelsTableMessages)
  const resolvedTitle = title ?? t.title
  const resolvedSearchPlaceholder = searchPlaceholder ?? t.searchPlaceholder
  const isSearchControlled = searchQuery !== undefined
  const [internalSearch, setInternalSearch] = React.useState(defaultSearchQuery)
  const resolvedSearch = isSearchControlled ? searchQuery : internalSearch

  const isExpandControlled = expandedIds !== undefined
  const [internalExpanded, setInternalExpanded] = React.useState<string[]>(
    defaultExpandedIds ?? []
  )
  const resolvedExpanded = isExpandControlled ? expandedIds : internalExpanded
  const expandedSet = React.useMemo(() => new Set(resolvedExpanded), [resolvedExpanded])

  const [sortDirection, setSortDirection] = React.useState<
    false | "asc" | "desc"
  >(false)

  const handleSearchChange = (value: string) => {
    if (!isSearchControlled) setInternalSearch(value)
    onSearchChange?.(value)
  }

  const commitExpanded = React.useCallback(
    (next: string[]) => {
      if (!isExpandControlled) setInternalExpanded(next)
      onExpandedChange?.(next)
    },
    [isExpandControlled, onExpandedChange]
  )

  const toggleExpanded = React.useCallback(
    (id: string) => {
      const next = expandedSet.has(id)
        ? resolvedExpanded.filter((value) => value !== id)
        : [...resolvedExpanded, id]
      commitExpanded(next)
    },
    [expandedSet, resolvedExpanded, commitExpanded]
  )

  const visibleRows = React.useMemo(() => {
    let next = [...rows]
    const query = resolvedSearch.trim().toLowerCase()

    if (query) {
      next = next.filter(
        (row) =>
          row.name.toLowerCase().includes(query) ||
          row.namespace.toLowerCase().includes(query) ||
          row.kind.toLowerCase().includes(query) ||
          row.type.toLowerCase().includes(query)
      )
    }

    if (enableSort && sortDirection) {
      next.sort((a, b) => {
        const cmp = a.name.localeCompare(b.name)
        return sortDirection === "asc" ? cmp : -cmp
      })
    }

    return next
  }, [rows, resolvedSearch, enableSort, sortDirection])

  const maxRuntimeMs = React.useMemo(
    () =>
      Math.max(
        ...visibleRows
          .filter((row) => row.runtimeMs != null && !row.hasError)
          .map((row) => row.runtimeMs as number),
        1
      ),
    [visibleRows]
  )

  const toggleSort = () => {
    setSortDirection((current) => {
      if (current === false) return "asc"
      if (current === "asc") return "desc"
      return false
    })
  }

  const columnCount = 6

  return (
    <section className={cn("w-full min-w-0", className)}>
      <div className="mb-4 flex flex-col gap-3 sm:mb-5 sm:flex-row sm:items-center sm:justify-between">
        <h3 className="text-muted-foreground text-[11px] font-semibold tracking-[0.14em] uppercase">
          {resolvedTitle}
        </h3>
        {enableSearch ? (
          <div className="relative w-full sm:max-w-[15rem]">
            <SearchIcon className="pointer-events-none absolute top-1/2 start-3 size-4 -translate-y-1/2 text-[#8c8c8c]" />
            <Input
              value={resolvedSearch}
              onChange={(event) => handleSearchChange(event.target.value)}
              placeholder={resolvedSearchPlaceholder}
              className="h-9 rounded-full border border-black/10 bg-white ps-9 text-sm text-[#242422] shadow-sm placeholder:text-[#8c8c8c] dark:border-transparent dark:bg-white dark:text-[#242422]"
            />
          </div>
        ) : null}
      </div>

      <div className="overflow-x-auto rounded-lg border border-grey-8">
        <Table
          noWrapper
          className="w-full min-w-[56rem] table-fixed [&_[data-slot=table-row]]:bg-transparent"
        >
          <colgroup>
            <col className="w-[33%]" />
            <col className="w-[20%]" />
            <col className="w-[15%]" />
            <col className="w-[11%]" />
            <col className="w-[13%]" />
            <col className="w-[8%]" />
          </colgroup>
          <TableHeader className="[&_tr]:border-b-2 [&_tr]:border-border">
            <TableRow className="border-border bg-transparent hover:bg-transparent">
              <TableHead className="text-foreground h-11 w-[33%] px-3 font-semibold sm:px-4">
                <div className="flex items-center justify-between gap-2">
                  <div className="flex items-center gap-2">
                    <ListIcon className="text-muted-foreground size-4 shrink-0" />
                    <span>
                      {t.columnModel}
                      <span className="text-muted-foreground ml-1 font-normal">
                        ({rows.length})
                      </span>
                    </span>
                  </div>
                  {enableSort ? (
                    <button
                      type="button"
                      className={headerIconClassName}
                      onClick={toggleSort}
                      aria-label={t.sortModels}
                    >
                      <ColumnSortIcon direction={sortDirection} />
                    </button>
                  ) : null}
                </div>
              </TableHead>
              <TableHead className="text-foreground relative h-11 w-[20%] px-3 font-semibold sm:px-4">
                <HeaderDivider />
                <div className="flex items-center justify-between gap-2">
                  <span className="whitespace-nowrap">{t.columnKindType}</span>
                  <HeaderFilterButton label={t.filterKindType} />
                </div>
              </TableHead>
              <TableHead className="text-foreground relative h-11 w-[15%] px-3 font-semibold sm:px-4">
                <HeaderDivider />
                <div className="flex items-center justify-between gap-2">
                  <span>{t.columnRuntime}</span>
                  <HeaderFilterButton label={t.filterRuntime} />
                </div>
              </TableHead>
              <TableHead className="text-foreground relative h-11 w-[11%] px-3 font-semibold sm:px-4">
                <HeaderDivider />
                <div className="flex items-center justify-between gap-2">
                  <span>{t.columnRows}</span>
                  <HeaderFilterButton label={t.filterRows} />
                </div>
              </TableHead>
              <TableHead className="text-foreground relative h-11 w-[13%] px-3 font-semibold sm:px-4">
                <HeaderDivider />
                <div className="flex items-center justify-between gap-2">
                  <span>{t.columnStatus}</span>
                  <HeaderFilterButton label={t.filterStatus} />
                </div>
              </TableHead>
              <TableHead className="relative h-11 w-[8%] px-2 sm:px-3">
                <HeaderDivider />
              </TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {visibleRows.length ? (
              visibleRows.map((row) => {
                const expandable = isExpandable(row)
                const expanded = enableExpand && expandable && expandedSet.has(row.id)

                if (expanded) {
                  return (
                    <ModelTableExpandedRow
                      key={row.id}
                      row={row}
                      columnCount={columnCount}
                      onToggleExpand={() => toggleExpanded(row.id)}
                    />
                  )
                }

                return (
                  <ModelTableDataRow
                    key={row.id}
                    row={row}
                    maxRuntimeMs={maxRuntimeMs}
                    expanded={expanded}
                    expandable={expandable}
                    enableExpand={enableExpand}
                    onToggleExpand={() => toggleExpanded(row.id)}
                  />
                )
              })
            ) : (
              <TableRow>
                <TableCell colSpan={columnCount} className="h-24 text-center">
                  {t.noModelsFound}
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>
    </section>
  )
}
